-- Turkish NPC Spawner - Client Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal SpawnedPeds = {}\n\nlocal TurkishNPCs = {\n    {name = 'Taksi Sefi', model = 'a_m_m_business_1', x = 425.5, y = -980.2, z = 28.4, h = 180.0},\n    {name = 'Polis Memuru', model = 'a_m_m_business_2', x = 430.0, y = -950.0, z = 25.0, h = 270.0},\n    {name = 'Eminonu Satıcisi', model = 'a_m_m_business_1', x = -520.5, y = -1020.3, z = 22.0, h = 90.0},\n    {name = 'Kadikoy Rehberi', model = 'a_f_m_business_1', x = 1150.0, y = -800.0, z = 57.6, h = 270.0},\n    {name = 'Mekanik Ustasi', model = 'a_m_m_business_1', x = 410.0, y = -920.0, z = 29.0, h = 90.0},\n}\n\nlocal function SpawnPed(pedData)\n    local modelHash = GetHashKey(pedData.model)\n    RequestModel(modelHash)\n    local timeout = 0\n    \n    while not HasModelLoaded(modelHash) and timeout < 10000 do\n        Wait(10)\n        timeout = timeout + 10\n    end\n    \n    if not HasModelLoaded(modelHash) then return nil end\n    \n    local ped = CreatePed(4, modelHash, pedData.x, pedData.y, pedData.z, pedData.h, true, false)\n    SetBlockingOfNonTemporaryEvents(ped, true)\n    TaskStartScenarioInPlace(ped, 'WORLD_HUMAN_STUPOR', 0, true)\n    table.insert(SpawnedPeds, ped)\n    return ped\nend\n\nCreateThread(function()\n    Wait(2000)\n    for i, pedData in ipairs(TurkishNPCs) do\n        SpawnPed(pedData)\n        Wait(100)\n    end\n    print('^2[Turkish NPC] ' .. #TurkishNPCs .. ' NPC yuklendi!^7')\nend)\n\nprint('^2[Turkish NPC Spawner] Yuklendi!^7')"